args.sparql:
SELECT ?player ?playerLabel ?amount WHERE {
  ?player wdt:P106 wd:Q3665655; # Occupation: basketball player
         wdt:P54/wdt:P118 wd:Q155223. # Team in NBA league
  ?player p:P3618/psv:P3618 ?amountNode.
  ?amountNode wikibase:quantityAmount ?amount;
              wikibase:quantityUnit wd:Q4917. # USD
  OPTIONAL { ?player rdfs:label ?playerLabel FILTER(LANG(?playerLabel) = 'en') }.
}
ORDER BY DESC(xsd:decimal(?amount))
LIMIT 1

best_attempt.sparql:
SELECT ?player ?playerLabel (MAX(xsd:decimal(?amount)) AS ?maxSalary) WHERE {
  ?player wdt:P106 wd:Q3665655; # basketball player
         wdt:P54/wdt:P118 wd:Q155223. # plays for NBA team
  ?player p:P3618/psv:P3618 ?amountNode.
  ?amountNode wikibase:quantityAmount ?amount;
              wikibase:quantityUnit wd:Q4917. # USD
  OPTIONAL { ?player rdfs:label ?playerLabel FILTER(LANG(?playerLabel) = 'en') }
}
ORDER BY DESC(?maxSalary)
LIMIT 1
